    int32 Dist = FLFPHexCoordinates::Distance(
        Caster->GetCurrentCoordinates(),
        Target->GetCurrentCoordinates()
    );
    float DistanceFactor = 1.0f / FMath::Max(Dist, 1);

    return Hatred * DistanceFactor;
}

